const Notification = require('../models/notificationModel');
const { io } = require('../server');

const createNewComment = async (commentData, board, author, recipientUser) => {
  const comment = { ...commentData, author: author.displayName };

  const newNotification = await Notification.create({
    recipient: recipientUser._id,
    sender: author._id,
    type: 'card_comment',
    content: `${author.displayName} đã bình luận về một thẻ bạn theo dõi.`
  });

  io.to(recipientUser._id.toString()).emit('new_notification', newNotification);

  return comment;
};

